func (this *ExtendedCore) ParseMarket(market any) any {
	//
	//     {
	//       "name": "BTC-USD",
	//       "uiName": "BTC-USD",
	//       "category": "Crypto",
	//       "subCategory": "L1",
	//       "assetName": "BTC",
	//       "assetPrecision": 5,
	//       "collateralAssetName": "USD",
	//       "collateralAssetPrecision": 6,
	//       "description": "Bitcoin",
	//       "active": true,
	//       "status": "ACTIVE",
	//       "marketStats": { ... },
	//       "tradingConfig": {
	//         "minOrderSize": "0.0001",
	//         "minOrderSizeChange": "0.00001",
	//         "minPriceChange": "1",
	//         "maxMarketOrderValue": "3000000",
	//         "maxLimitOrderValue": "15000000",
	//         "maxPositionValue": "60000000",
	//         "maxLeverage": "50.00",
	//         "hourlyFundingRateCap": "0.25",
	//         "maxNumOrders": "200",
	//         "limitPriceCap": "0.05",
	//         "limitPriceFloor": "0.05",
	//         "riskFactorConfig": [
	//           {
	//             "upperBound": "4000000",
	//             "riskFactor": "0.02",
	//             "isAvailableForUsers": true
	//           }
	//         ]
	//       },
	//       "l2Config": { ... },
	//       "visibleOnUi": true,
	//       "createdAt": 1752829532673
	//     }
	//
	var tradingConfig any = this.SafeDict(market, "tradingConfig", map[string]any{})
	var marketId any = this.SafeString(market, "name")
	var baseId any = this.SafeString(market, "assetName", "")
	if IsTrue(IsGreaterThanOrEqual(GetIndexOf(baseId, "SPOT"), 0)) {
		baseId = Replace(baseId, "SPOT", "")
	}
	var quoteId any = this.SafeString(market, "collateralAssetName")
	var base any = this.SafeCurrencyCode(baseId)
	var quote any = this.SafeCurrencyCode(quoteId)
	if IsTrue(IsEqual(quoteId, "USD")) {
		quote = "USDC"
	}
	var status any = this.SafeString(market, "status")
	var active any = (IsEqual(status, "ACTIVE"))
	var amountPrecision any = this.SafeNumber(tradingConfig, "minOrderSizeChange")
	var pricePrecision any = this.SafeNumber(tradingConfig, "minPriceChange")
	var maxLeverage any = this.SafeNumber(tradingConfig, "maxLeverage")
	var minAmount any = this.SafeNumber(tradingConfig, "minOrderSize")
	var maxCost any = this.SafeNumber(tradingConfig, "maxLimitOrderValue")
	var created any = this.SafeInteger(market, "createdAt")
	var settleId any = nil
	var settle any = nil
	var symbol any = Add(Add(base, "/"), quote)
	var isSpot any = false
	var typeVar any = this.SafeStringLower(market, "type")
	var contractSize any = nil
	var linear any = nil
	var inverse any = nil
	if IsTrue(IsEqual(typeVar, "spot")) {
		isSpot = true
	} else {
		typeVar = "swap"
		settleId = quoteId
		settle = quote
		symbol = Add(symbol, Add(":", settle))
		contractSize = this.ParseNumber("1")
		linear = true
		inverse = false
	}
	return this.SafeMarketStructure(map[string]any{
		"id":             marketId,
		"symbol":         symbol,
		"base":           base,
		"quote":          quote,
		"settle":         settle,
		"baseId":         baseId,
		"quoteId":        quoteId,
		"settleId":       settleId,
		"type":           typeVar,
		"spot":           isSpot,
		"margin":         false,
		"swap":           !IsTrue(isSpot),
		"future":         false,
		"option":         false,
		"active":         active,
		"contract":       !IsTrue(isSpot),
		"linear":         linear,
		"inverse":        inverse,
		"taker":          this.SafeNumber(this.Fees, "taker"),
		"maker":          this.SafeNumber(this.Fees, "maker"),
		"contractSize":   contractSize,
		"expiry":         nil,
		"expiryDatetime": nil,
		"strike":         nil,
		"optionType":     nil,
		"precision": map[string]any{
			"amount": amountPrecision,
			"price":  pricePrecision,
		},
		"limits": map[string]any{
			"leverage": map[string]any{
				"min": this.ParseNumber("1"),
				"max": maxLeverage,
			},
			"amount": map[string]any{
				"min": minAmount,
				"max": nil,
			},
			"price": map[string]any{
				"min": nil,
				"max": nil,
			},
			"cost": map[string]any{
				"min": nil,
				"max": maxCost,
			},
		},
		"created": created,
		"info":    market,
	})
}

